diff --git a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
index a88f8f19f852..f5db1f16d66e 100644
--- a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
+++ b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@ -603,10 +603,19 @@ APInt ConstantOffsetExtractor::find(Value *V, bool SignExtended,
     // Handle XOR with disjoint bits that can be treated as addition.
     else if (BO->getOpcode() == Instruction::Xor)
       ConstantOffset = extractDisjointBitsFromXor(BO);
-  } else if (isa<TruncInst>(V)) {
-    ConstantOffset =
-        find(U->getOperand(0), SignExtended, ZeroExtended, NonNegative)
-            .trunc(BitWidth);
+  } else if (auto *TI = dyn_cast<TruncInst>(V)) {
+    // We can't trace through a trunc if it has nsw/nuw flags and its operand
+    // is a binary operator, because trunc(op(X,C)) may be valid whereas
+    // op(trunc(X), C) may not be. For example, trunc(add(X,C)) is not
+    // equivalent to add(trunc(X), trunc(C)) with nsw flags.
+    if ((TI->hasNoSignedWrap() || TI->hasNoUnsignedWrap()) &&
+        isa<BinaryOperator>(U->getOperand(0))) {
+      ConstantOffset = APInt(BitWidth, 0);
+    } else {
+      ConstantOffset =
+          find(U->getOperand(0), SignExtended, ZeroExtended, NonNegative)
+              .trunc(BitWidth);
+    }
   } else if (isa<SExtInst>(V)) {
     ConstantOffset = find(U->getOperand(0), /* SignExtended */ true,
                           ZeroExtended, NonNegative).sext(BitWidth);

